$subf = null;
$find = array();
preg_match_all("/\(Subcategory~equals~(.+)\)/U",postvalue("f"),$find);
if(count($find[1]) > 0 && isset($find[1][0]))
	$subf  = $find[1][0];
$cat_rs = DB::Select("tahun");
$links_arr = array();
$main_link = GetTableLink("data_sibay","list");
$links_arr["all"] = array("link" => $main_link,"label" => "SEMUA", "class" => "","nsm" => array() );
while($cat = $cat_rs->fetchAssoc()){
	$links_arr[$cat["nama Madrasah"]] = array("link" => $main_link."?f=(tahun~equals~".rawurlencode($cat["nama Madrasah"]).")","label" => $cat["nama Madrasah"], "class" => "","nsm" => array() );
	$subcat_rs = DB::Select("nsm",array("tahun" => $cat["nama Madrasah"]));
	while($subcat = $subcat_rs->fetchAssoc()){
				$subcat_count_rs = DB::Select("data_sibay",array("nsm" => $subcat["nama Madrasah"] ));
				$subcat_count = $subcat_count_rs->fetchAssoc();
				if(!$subcat_count) continue;
				$links_arr[$cat["nama Madrasah"]]["nsm"][$subcat["nsm"]] = array("link" => $main_link."?f=(nsm~equals~".rawurlencode($subcat["nama Madrasah"]).")","label" => $subcat["nama Madrasah"], "class" => "" );
				if($subf === $subcat["nama Madrasah"]) {
					$links_arr[$cat["nama Madrasah"]]["nsm"][$subcat["nsm"]]["class"] = "active";
					$links_arr[$cat["nama Madrasah"]]["class"] = "active";
				}
	}

}
$catf = null;
$find = array();
preg_match_all("/\(tahun~equals~(.+)\)/U",postvalue("f"),$find);
if(count($find[1]) > 0 && isset($find[1][0]))
{
	$catf = $find[1][0];
	$links_arr[$find[1][0]]["class"] = "active";
}

if(is_null($subf) && is_null($catf)) 
	$links_arr["all"]["class"] = "active";
foreach($links_arr as $link){
	echo "<span class='".$link["class"]."'><a href='".$link["link"]."'>".$link["label"]."</a>";
	if(count($link["tahun"])){
		echo "<ul class='nsm'>";
		foreach($link["nsm"] as $nsm)
			echo "<li class='".$nsm["class"]."'><a href='".$nsm["link"]."'>".$nsm["label"]."</a></li>";
		echo "</ul>";
	}
	echo  "</span>";
}
